import { Hono } from 'hono';
import Stripe from 'stripe';

const app = new Hono();

app.post('/create-subscription', async (c) => {
  const stripeApiKey = process.env.STRIPE_API_KEY;
  if (!stripeApiKey) {
    return c.status(500).json({ error: 'Stripe API key not provided' });
  }

  const stripe = new Stripe(stripeApiKey, { apiVersion: '2023-08-16' });

  try {
    // Assuming the user ID is passed in the request body
    const userId = c.req.body('userId');
    if (!userId) {
      return c.status(400).json({ error: 'User ID is required' });
    }

    // Create a customer (if not already created)
    let customer;
    try {
      customer = await stripe.customers.retrieve(userId);
    } catch (error) {
      if (error.type === 'StripeError' && error.code === 'resource_missing') {
        customer = await stripe.customers.create({ id: userId });
      } else {
        throw error;
      }
    }

    // Create a subscription
    const subscription = await stripe.subscriptions.create({
      customer: customer.id,
      items: [
        { price: process.env.STRIPE_PRICE_ID }, // Replace with your actual price ID
      ],
    });

    // Store the subscription ID locally (e.g., in a database)
    // For demonstration, we'll just log it
    console.log('Subscription created:', subscription.id);

    return c.json({ subscriptionId: subscription.id });
  } catch (error) {
    if (error instanceof Stripe.errors.StripeError) {
      return c.status(error.statusCode).json({ error: error.message });
    }
    return c.status(500).json({ error: 'Internal server error' });
  }
});

export default app;

